  if (isEmptySet())
    return KnownBits(getBitWidth());

  APInt UMin = getUnsignedMin();
  APInt UMax = getUnsignedMax();
  APInt UMask = UMin ^ UMax;

  APInt SMin = getSignedMin();
  APInt SMax = getSignedMax();
  APInt SMask = SMin ^ SMax;

